const event = $input.first().json;

return [{
  json: {
    pachca_user_id: event.user_id,
    answer_data: event.data,
    message_id: event.message_id,
    chat_id: event.chat_id,
    event_type: event.type
  }
}];

const question = $('Текущий вопрос (ответ)').first().json;
const session = JSON.parse($('GET сессия (ответ)').first().json.propertyName);
const webhookData = $('Парсинг вебхука').first().json;

const answers = JSON.parse(session.answers || '{}');
const questionIds = session.question_ids.split(',').map(id => id.trim());
const currentQuestionId = questionIds[Number(session.current_question_index)];
answers[currentQuestionId] = webhookData.answer_data;

const answerMap = {
  'A': question.вариант_A,
  'B': question.вариант_B,
  'C': question.вариант_C,
  'D': question.вариант_D
};

const isCorrect = webhookData.answer_data === question.правильный_ответ;
const earnedScore = isCorrect ? (Number(question.вес_баллов) || 1) : 0;
const newIndex = Number(session.current_question_index) + 1;
const isLastQuestion = newIndex >= Number(session.total_questions) ? 'true' : 'false';
const totalScore = Number(session.total_score || 0) + earnedScore;
const maxScore = Number(session.max_score || 0) + (Number(question.вес_баллов) || 1);

return [{ json: {
  session_id: session.session_id,
  employee_id: session.employee_id,
  ФИО: session.ФИО,
  pachca_user_id: session.pachca_user_id,
  цикл: session.цикл,
  номер_теста: session.номер_теста,
  номер_попытки: session.номер_попытки,
  целевая_аудитория: session.целевая_аудитория,
  question_ids: session.question_ids,
  questions_data: session.questions_data,
  current_question_index: newIndex,
  total_questions: Number(session.total_questions),
  correct_answer: answerMap[question.правильный_ответ] || question.правильный_ответ,
  question_weight: Number(question.вес_баллов) || 1,
  answers: JSON.stringify(answers),
  is_last_question: isLastQuestion,
  total_score: totalScore,
  max_score: maxScore,
  current_question_id: currentQuestionId,
  question_text: question.текст_вопроса,
  answer_data: answerMap[webhookData.answer_data] || webhookData.answer_data,
  is_correct: isCorrect,
  reminder_count: session.reminder_count ?? 0
} }];

const fixation = $('Фиксация ответа').first().json;
const answers = JSON.parse(fixation.answers || '{}');
const questionIds = fixation.question_ids.split(',').map(id => id.trim());
const sessionForReminder = JSON.parse($('GET сессия (ответ)').first().json.propertyName);

const totalScore = Number(fixation.total_score || 0);
const maxScore = Number(fixation.max_score || questionIds.length);
const scorePercent = Math.round((totalScore / maxScore) * 100);
const status = scorePercent >= 1 ? 'пройден' : 'не пройден';

return [{
  json: {
    session_id: fixation.session_id,
    employee_id: fixation.employee_id,
    ФИО: fixation.ФИО,
    pachca_user_id: fixation.pachca_user_id,
    цикл: fixation.цикл,
    номер_теста: fixation.номер_теста,
    номер_попытки: fixation.номер_попытки,
    целевая_аудитория: fixation.целевая_аудитория,
    score: scorePercent,
    статус: status,
    answers: fixation.answers,
    question_ids: fixation.question_ids,
    total_score: fixation.total_score,
    max_score: maxScore,
    reminder_count: sessionForReminder.reminder_count ?? 0
  }
}];

const result = $('Итог теста').first().json;
const session = JSON.parse($('GET сессия (ответ)').first().json.propertyName);
const questionsData = JSON.parse(session.questions_data);
const answers = JSON.parse(result.answers || '{}');
const questionIds = result.question_ids.split(',').map(id => id.trim());

const mistakes = questionIds
  .filter(qid => {
    const userAnswer = answers[qid];
    const correct = questionsData[qid]?.правильный_ответ;
    return userAnswer !== correct;
  })
  .map(qid => {
    const q = questionsData[qid];
    const link = q.инструкция_БЗ ? `\n📖 ${q.инструкция_БЗ}` : '';
    return `❌ ${q.текст_вопроса}${link}`;
  });

const filled = Math.round(result.score / 10);
const empty = 10 - filled;
const progressBar = '🟦'.repeat(filled) + '⬜'.repeat(empty);
const scoreEmoji = result.score >= 80 ? '🟢' : result.score >= 70 ? '🟡' : '🔴';

let content = `────────────────\n✅ **Тест завершён!**\n\n${progressBar} ${scoreEmoji} **${result.score}%**`;

if (mistakes.length > 0) {
  const mistakesList = mistakes.join('\n\n');
  content += `\n\n────────────────\n📋 **Что изучить:**\n\n${mistakesList}`;
} else {
  content += `\n\n────────────────\n🎉 Все ответы верные!`;
}

const body = {
  message: {
    entity_type: 'user',
    entity_id: Number(result.pachca_user_id),
    content: content
  }
};

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.pachca.com/api/shared/v1/messages',
  headers: {
    'Authorization': 'Bearer ' + $env.PACHCA_TOKEN + '',
    'Content-Type': 'application/json'
  },
  body: body
});

return [{ json: { done: true } }];

const question = $input.first().json;
const questionNumber = Number(question.current_question_index) + 1;
const total = question.total_questions;

const buttons = [
  [{ text: `${question.вариант_A}`, data: 'A' }],
  [{ text: `${question.вариант_B}`, data: 'B' }],
  [{ text: `${question.вариант_C}`, data: 'C' }],
  [{ text: `${question.вариант_D}`, data: 'D' }]
];

let response;
try {
  response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.pachca.com/api/shared/v1/messages',
    headers: {
      'Authorization': 'Bearer ' + $env.PACHCA_TOKEN + '',
      'Content-Type': 'application/json'
    },
    body: {
      message: {
        entity_type: 'user',
        entity_id: Number(question.pachca_user_id),
        content: `📋 Вопрос ${questionNumber} из ${total}\n\n${question.текст_вопроса}\n\nВыбери один вариант ответа:`,
        buttons: buttons
      }
    }
  });
} catch(e) {
  return [{ json: { error: e.message } }];
}

return [{ json: { done: true, last_message_id: response.data.id, session_id: question.session_id } }];

