const fixation = $('Фиксация ответа').first().json;
const questionsData = JSON.parse(fixation.questions_data);
const nextQuestionId = fixation.question_ids.split(',').map(id => id.trim())[fixation.current_question_index];
const question = questionsData[nextQuestionId];

return [{
  json: {
    ...question,
    session_id: fixation.session_id,
    employee_id: fixation.employee_id,
    pachca_user_id: fixation.pachca_user_id,
    question_ids: fixation.question_ids,
    questions_data: fixation.questions_data,
    current_question_index: fixation.current_question_index,
    total_questions: fixation.total_questions,
    answers: fixation.answers,
    current_question_id: nextQuestionId
  }
}];

const webhookData = $('Парсинг вебхука').first().json;
const token = 'Bearer ' + $env.PACHCA_TOKEN + '';
const sessionIdRaw = $('get session_id (старт)').first().json.propertyName ?? '';

// 1. Тест завершён
if (sessionIdRaw.startsWith('завершён:')) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `https://api.pachca.com/api/shared/v1/messages/${webhookData.message_id}`,
      headers: { 'Authorization': token, 'Content-Type': 'application/json' },
      body: { message: { content: '✅ Тест уже пройден', buttons: [] } }
    });
  } catch(e) {}
  return [];
}

// 2. Нет сессии
if (!sessionIdRaw) return [];

const sessionRaw = ($('GET сессия (старт)').first().json.propertyName ?? '').replace(/^=/, '');
if (!sessionRaw) return [];
const session = JSON.parse(sessionRaw);

// 3. Тест уже идёт — проверяем ДО last_message_id
if (session.статус === 'в процессе') {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `https://api.pachca.com/api/shared/v1/messages/${webhookData.message_id}`,
      headers: { 'Authorization': token, 'Content-Type': 'application/json' },
      body: { message: { content: '📋 Ты уже проходишь тест — ответь на текущий вопрос.', buttons: [] } }
    });
  } catch(e) {}
  return [];
}

// 4. Устаревшая кнопка
if (session.last_message_id && String(session.last_message_id) !== String(webhookData.message_id)) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `https://api.pachca.com/api/shared/v1/messages/${webhookData.message_id}`,
      headers: { 'Authorization': token, 'Content-Type': 'application/json' },
      body: { message: { content: '⚠️ Используй актуальную кнопку ниже.', buttons: [] } }
    });
  } catch(e) {}
  return [];
}

return [{ json: webhookData }];

